@charset "UTF-8";
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap");
/*======================================
Variables globales (Harmonisées)
======================================*/
:root {
  --font-primary: "Poppins", sans-serif;
  --color-text-dark: #39444D;
  --color-text-gray: #6B7280;
  --color-bg: #ffffff;
  --color-bg-gray-light: #F9FAFB;
  --color-border: #E5E7EB;
  --color-pill-true-bg: #ECFDF5;
  --color-pill-true-text: #007A56;
  --color-pill-false-bg: #FEF2F2;
  --color-pill-false-text: #EF4444;
  --color-pill-neutral-bg: #F3F4F6;
  --color-pill-neutral-text: #4B5563;
  --color-primary: #82DB34;
  --color-primary-hover: #75C62F;
  --radius-main: 12px;
  --radius-pill: 20px;
}

body, html {
  margin: 0;
  padding: 0;
  height: auto;
  /* On force la disparition de la barre de scroll du navigateur */
  overflow: hidden !important;
}

#root {
  height: auto;
  overflow: hidden;
  /* Petit coussin pour absorber l'arrondi de calcul d'Appsmith */
  padding-bottom: 4px;
}

.modal-container {
  font-family: var(--font-primary);
  display: flex;
  flex-direction: column;
  padding: 12px;
  gap: 24px;
  text-align: center;
  box-sizing: border-box;
}

/*======================================
  Titre
======================================*/
.modal-title {
  font-size: 1.4rem;
  font-weight: 700;
  color: var(--color-text-dark);
  margin: 0;
  line-height: 1.3;
}

/*======================================
  Encart Financier (Dynamique)
======================================*/
.financial-box {
  padding: 16px;
  border-radius: var(--radius-main);
  font-size: 1.1rem;
  font-weight: 500;
}

.financial-box b {
  font-weight: 700;
  font-size: 1.2rem;
}

.financial-box.success {
  background-color: var(--color-pill-true-bg);
  color: var(--color-pill-true-text);
}

.financial-box.warning {
  background-color: var(--color-pill-false-bg);
  color: var(--color-pill-false-text);
}

.financial-box.neutral {
  background-color: var(--color-pill-neutral-bg);
  color: var(--color-pill-neutral-text);
}

/*======================================
  Encart Réassurance
======================================*/
.reassurance-list {
  display: flex;
  flex-direction: column;
  gap: 16px;
  background-color: var(--color-bg-gray-light);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-main);
  padding: 20px;
  text-align: left;
}

.reassurance-item {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--color-text-dark);
}

.reassurance-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

/*======================================
  Actions (Boutons)
======================================*/
.modal-actions {
  display: flex;
  justify-content: flex-end; /* Aligne les boutons à droite */
  gap: 12px;
  width: 100%;
  margin-top: 12px;
}

.btn-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 20px; /* Boutons légèrement moins hauts */
  font-family: var(--font-primary);
  font-weight: 600;
  font-size: 0.95rem; /* Texte légèrement plus petit */
  border: none;
  border-radius: var(--radius-pill);
  cursor: pointer;
  transition: all 0.2s ease;
  width: auto; /* Prennent juste leur taille naturelle */
}

/* Bouton Gris (Retour) */
.btn-cta--grey {
  color: var(--color-text-gray);
  border: 1px solid var(--color-border);
  background: var(--color-bg-gray-light);
}

.btn-cta--grey:hover {
  background-color: var(--color-border);
  color: var(--color-text-dark);
}

/* Bouton Primaire (C'est parti) */
.btn-cta--primary {
  background-color: var(--color-primary);
  color: white;
  position: relative;
  overflow: hidden;
}

.btn-cta--primary:hover {
  background-color: var(--color-primary-hover);
}

.btn-cta--primary::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 50%;
  height: 100%;
  background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.4) 50%, rgba(255, 255, 255, 0) 100%);
  transform: skewX(-20deg);
  transition: left 0.6s ease-in-out;
}

.btn-cta--primary:hover::after {
  left: 150%;
}

/* Responsive Mobile */
@media screen and (max-width: 480px) {
  .modal-actions {
    flex-direction: column-reverse; /* Met le bouton retour en bas sur mobile */
  }
  .btn-cta {
    width: 100%; /* Boutons pleine largeur sur mobile */
  }
}

