	<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="var(--color-primary)" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
		<polyline points="20 6 9 17 4 12"></polyline>
	</svg>
);

const IconStar = () => (
	<svg width="22" height="22" viewBox="0 0 24 24" fill="#FBBF24" stroke="#FBBF24" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
		<polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon>
	</svg>
);

// --- Composant Principal ---
function ModalContent() {
	// Récupération des données du modèle Appsmith
	const rawSavings = appsmith.model.computedSavings || "0";

	// On transforme la string en nombre (en gérant la virgule éventuelle)
	const savingsValue = parseFloat(String(rawSavings).replace(',', '.'));

	// Formatage propre pour l'affichage (remet la virgule et gère les espaces des milliers)
	const formattedSavings = Math.abs(savingsValue).toLocaleString('fr-FR', { 
		minimumFractionDigits: Number.isInteger(Math.abs(savingsValue)) ? 0 : 2, 
		maximumFractionDigits: 2 
	});

	// Logique d'affichage dynamique de l'encart financier
	let financialElement = null;
	if (savingsValue > 0) {
		financialElement = (
			<div className="financial-box success">
				Vous allez réaliser <b>{formattedSavings} € par an</b> d'économies ! 🎉
			</div>
		);
	} else if (savingsValue < 0) {
		financialElement = (
			<div className="financial-box warning">
				Cette offre représente un surcoût de <b>{formattedSavings} € par an</b>.
			</div>
		);
	} else {
		financialElement = (
			<div className="financial-box neutral">
				Le tarif de cette offre est <b>identique</b> à votre assurance actuelle.
			</div>
		);
	}

	return (
		<div className="modal-container">

			<h2 className="modal-title">Confirmez-vous le choix de cette assurance ?</h2>

			{/* Encart dynamique */}
			{financialElement}

			{/* Encart Réassurance */}
			<div className="reassurance-list">
				<div className="reassurance-item">
					<span className="reassurance-icon"><IconCheck /></span>
					Ideel s'occupe de tout l'administratif
				</div>
				<div className="reassurance-item">
					<span className="reassurance-icon"><IconCheck /></span>
					Aucune coupure de garanties
				</div>
				<div className="reassurance-item">
					<span className="reassurance-icon"><IconStar /></span>
					Ideel est noté 4,9 / 5
				</div>
			</div>

			{/* Boutons */}
			<div className="modal-actions">
				<button 
					className="btn-cta btn-cta--grey"
					onClick={() => appsmith.triggerEvent("closeModal")}
				>
					Retour
				</button>
				<button 
					className="btn-cta btn-cta--primary"
					onClick={() => appsmith.triggerEvent("confirm")}
				>
					C'est parti !
				</button>
			</div>

		</div>
	);
}

function renderApp() {
	ReactDOM.render(<ModalContent />, document.getElementById("root"));
}

appsmith.onReady(() => renderApp());
appsmith.onModelChange(() => renderApp());
